export interface User {
  id: string;
  email: string;
  name: string;
  credits: number;
  plan: PlanTier;
}

export interface Recommendation {
  id: string;
  priority: 'critical' | 'high' | 'medium' | 'low';
  title: string;
  description: string;
  action: string;
  effort: 'low' | 'medium' | 'high';
  impact: 'low' | 'medium' | 'high';
  category: string;
}

export interface CategoryScore {
  name: string;
  score: number;
  weight: number;
  items: Array<{
    status: 'success' | 'warning' | 'error';
    message: string;
  }>;
}

export interface GeneratedSolution {
  title: string;
  explanation: string;
  content: string;
  type: 'code' | 'text';
  language?: 'html' | 'json' | 'text' | 'markdown';
  implementationSteps: string[];
}

export interface GraphNode {
  id: string;
  label: string;
  type: 'entity' | 'keyword' | 'competitor' | 'source';
  val: number;
}

export interface GraphLink {
  source: string;
  target: string;
  strength: number;
}

export interface AnalysisResult {
  url: string;
  timestamp: string;
  globalScore: number;
  categories: Record<string, CategoryScore>;
  recommendations: Recommendation[];
  aiCitation: {
    before: string;
    after: string;
    probability: number;
  };
  knowledgeGraph: {
    nodes: GraphNode[];
    links: GraphLink[];
  };
  generatedSolutions?: Record<string, GeneratedSolution & { timestamp: string }>;
}

export interface SMCContent {
  id: string;
  type: SMCContentType;
  title: string;
  content: string;
  timestamp: string;
}

export type SMCContentType = 'fiche' | 'faq' | 'brief' | 'article' | 'truth' | 'robots' | 'schema';

export interface ComparisonData {
  category: string;
  you: number;
  competitor: number;
}

export interface Notification {
  id: string;
  type: 'success' | 'error' | 'info';
  message: string;
}

export interface BackupData {
  user?: User;
  history?: AnalysisResult[];
  library?: SMCContent[];
}

// --- INDEXATION IA TYPES ---

export type AIBot = {
  id: string;
  name: string;
  provider: string;
  userAgent: string;
  purpose: 'training' | 'search' | 'both';
  respectsRobots: boolean;
};

export const AI_BOTS: AIBot[] = [
  { id: 'gptbot', name: 'GPTBot', provider: 'OpenAI', userAgent: 'GPTBot', purpose: 'training', respectsRobots: true },
  { id: 'chatgpt-user', name: 'ChatGPT-User', provider: 'OpenAI', userAgent: 'ChatGPT-User', purpose: 'search', respectsRobots: true },
