  { id: 'amazonbot', name: 'Amazonbot', provider: 'Amazon', userAgent: 'Amazonbot', purpose: 'both', respectsRobots: true },
  { id: 'meta-external', name: 'Meta-ExternalAgent', provider: 'Meta', userAgent: 'Meta-ExternalAgent', purpose: 'training', respectsRobots: true }
