     1→import React from 'react';
     2→import { Routes, Route, Navigate, useParams } from 'react-router-dom';
     3→import { AnalysisResult, GeneratedSolution, SMCContent, User } from '../types';
     4→import { ViewKey, VIEWS } from '../config/constants';
     5→import Home from '../legacy-pages/Home';
     6→import Login from '../legacy-pages/Login';
     7→import Dashboard from '../legacy-pages/Dashboard';
     8→import Projects from '../legacy-pages/Projects';
     9→import Analyze from '../legacy-pages/Analyze';
    10→import SMCStudio from '../legacy-pages/SMCStudio';
    11→import KnowledgeExplorer from '../legacy-pages/KnowledgeExplorer';
    12→import Benchmark from '../legacy-pages/Benchmark';
    13→import Account from '../legacy-pages/Account';
    14→import Payment from '../legacy-pages/Payment';
    15→import PaymentSuccess from '../legacy-pages/PaymentSuccess';
    16→import IndexationDashboard from '../legacy-pages/IndexationDashboard';
    17→import RobotsTxtAnalyzer from '../legacy-pages/RobotsTxtAnalyzer';
    18→import LlmsTxtGenerator from '../legacy-pages/LlmsTxtGenerator';
    19→import AiMetaTagsGenerator from '../legacy-pages/AiMetaTagsGenerator';
    20→import BotSimulator from '../legacy-pages/BotSimulator';
    21→import OrdersListPage from '../legacy-pages/agency/OrdersListPage';
    22→import OrderDetailPage from '../legacy-pages/agency/OrderDetailPage';
    23→import OrdersStatsPage from '../legacy-pages/agency/OrdersStatsPage';
    24→import AgencyServicesPage from '../legacy-pages/agency/AgencyServicesPage';
    25→import AgencyProfilePage from '../legacy-pages/agency/AgencyProfilePage';
    26→import BillingDashboard from '../legacy-pages/billing/BillingDashboard';
    27→import SubscriptionPage from '../legacy-pages/billing/SubscriptionPage';
    28→import InvoicesPage from '../legacy-pages/billing/InvoicesPage';
    29→import PayoutsPage from '../legacy-pages/billing/PayoutsPage';
    30→import CreditsPage from '../legacy-pages/billing/CreditsPage';
    31→import PaymentMethodsPage from '../legacy-pages/billing/PaymentMethodsPage';
    32→
    33→export interface CheckoutData {
    34→  planName: string;
    35→  price: number;
    36→  cycle: 'monthly' | 'yearly';
    37→}
    38→
    39→interface AppRouterProps {
    40→  user: User | null;
    41→  history: AnalysisResult[];
    42→  smcLibrary: SMCContent[];
    43→  analysisData: AnalysisResult | null;
    44→  isAnalyzing: boolean;
    45→  checkoutData: CheckoutData | null;
    46→  onNavigate: (view: ViewKey) => void;
    47→  onLogin: (user: User) => void;
    48→  onAnalyze: (url: string) => void;
    49→  onDeductCredits: (amount: number) => boolean;
    50→  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
    51→  onAddToLibrary: (item: SMCContent) => void;
    52→  onSelectAnalysis: (analysis: AnalysisResult) => void;
    53→  onNewAnalysis: () => void;
    54→  onConfirmSubscription: () => void;
    55→  onFinishPaymentFlow: () => void;
    56→  onLogout: () => void;
    57→  onUpdateUser: (updates: Partial<User>) => void;
    58→  notify: (type: 'success' | 'error' | 'info', message: string) => void;
    59→  onOpenOrder: (orderId: string) => void;
    60→}
    61→
    62→const RequireAuth: React.FC<{ user: User | null; children: React.ReactNode }> = ({ user, children }) => {
    63→  if (!user) {
    64→    return <Navigate to={VIEWS.LOGIN} replace />;
    65→  }
    66→  return <>{children}</>;
    67→};
    68→
    69→const RequireAgency: React.FC<{ user: User | null; children: React.ReactNode }> = ({ user, children }) => {
    70→  if (!user) {
    71→    return <Navigate to={VIEWS.LOGIN} replace />;
    72→  }
    73→  if (user.plan !== 'agency') {
    74→    return <Navigate to={VIEWS.DASHBOARD} replace />;
    75→  }
    76→  return <>{children}</>;
    77→};
    78→
    79→const AppRouter: React.FC<AppRouterProps> = ({
    80→  user,
    81→  history,
    82→  smcLibrary,
    83→  analysisData,
    84→  isAnalyzing,
    85→  checkoutData,
    86→  onNavigate,
    87→  onLogin,
    88→  onAnalyze,
    89→  onDeductCredits,
    90→  onSaveSolution,
    91→  onAddToLibrary,
    92→  onSelectAnalysis,
    93→  onNewAnalysis,
    94→  onConfirmSubscription,
    95→  onFinishPaymentFlow,
    96→  onLogout,
    97→  onUpdateUser,
    98→  notify,
    99→  onOpenOrder
   100→}) => {
   101→  const knowledgeTarget = analysisData || history[0];
   102→
   103→  const AgencyOrderRoute: React.FC = () => {
   104→    const { orderId } = useParams<{ orderId: string }>();
   105→    if (!orderId) {
   106→      return <Navigate to={VIEWS.AGENCY_ORDERS} replace />;
   107→    }
   108→    return <OrderDetailPage orderId={orderId} onBack={() => onNavigate(VIEWS.AGENCY_ORDERS)} />;
   109→  };
   110→
   111→  return (
   112→    <div className="flex-1 min-h-0">
   113→      <Routes>
   114→        <Route
   115→          path={VIEWS.HOME}
   116→          element={<Home onNavigate={onNavigate} user={user} onAnalyze={onAnalyze} isAnalyzing={isAnalyzing} />}
   117→        />
   118→        <Route
   119→          path={VIEWS.LOGIN}
   120→          element={user ? <Navigate to={user.credits === 0 ? VIEWS.BILLING_CREDITS : VIEWS.ANALYZE} replace /> : <Login onLogin={onLogin} onBack={() => onNavigate(VIEWS.HOME)} />}
   121→        />
   122→
   123→        <Route
   124→          path={VIEWS.DASHBOARD}
   125→          element={(
   126→            <RequireAuth user={user}>
   127→              <Dashboard
   128→                history={history}
   129→                onView={(res) => { onSelectAnalysis(res); onNavigate(VIEWS.PROJECTS); }}
   130→                onNavigate={onNavigate}
   131→              />
   132→            </RequireAuth>
   133→          )}
   134→        />
   135→        <Route
   136→          path={VIEWS.ANALYZE}
   137→          element={(
   138→            <RequireAuth user={user}>
   139→              <Analyze onAnalyze={onAnalyze} isAnalyzing={isAnalyzing} />
   140→            </RequireAuth>
   141→          )}
   142→        />
   143→        <Route
   144→          path={VIEWS.PROJECTS}
   145→          element={(
   146→            <RequireAuth user={user}>
   147→              <Projects
   148→                history={history}
   149→                user={user}
