import React from 'react';
import { Routes, Route, Navigate, useParams } from 'react-router-dom';
import { AnalysisResult, GeneratedSolution, SMCContent, User } from '../types';
import { ViewKey, VIEWS } from '../config/constants';
import Home from '../legacy-pages/Home';
import Login from '../legacy-pages/Login';
import Dashboard from '../legacy-pages/Dashboard';
import Projects from '../legacy-pages/Projects';
import Analyze from '../legacy-pages/Analyze';
import SMCStudio from '../legacy-pages/SMCStudio';
import KnowledgeExplorer from '../legacy-pages/KnowledgeExplorer';
import Benchmark from '../legacy-pages/Benchmark';
import Account from '../legacy-pages/Account';
import Payment from '../legacy-pages/Payment';
import PaymentSuccess from '../legacy-pages/PaymentSuccess';
import IndexationDashboard from '../legacy-pages/IndexationDashboard';
import RobotsTxtAnalyzer from '../legacy-pages/RobotsTxtAnalyzer';
import LlmsTxtGenerator from '../legacy-pages/LlmsTxtGenerator';
import AiMetaTagsGenerator from '../legacy-pages/AiMetaTagsGenerator';
import BotSimulator from '../legacy-pages/BotSimulator';
import OrdersListPage from '../legacy-pages/agency/OrdersListPage';
import OrderDetailPage from '../legacy-pages/agency/OrderDetailPage';
import OrdersStatsPage from '../legacy-pages/agency/OrdersStatsPage';
import AgencyServicesPage from '../legacy-pages/agency/AgencyServicesPage';
import AgencyProfilePage from '../legacy-pages/agency/AgencyProfilePage';
import BillingDashboard from '../legacy-pages/billing/BillingDashboard';
import SubscriptionPage from '../legacy-pages/billing/SubscriptionPage';
import InvoicesPage from '../legacy-pages/billing/InvoicesPage';
import PayoutsPage from '../legacy-pages/billing/PayoutsPage';
import CreditsPage from '../legacy-pages/billing/CreditsPage';
import PaymentMethodsPage from '../legacy-pages/billing/PaymentMethodsPage';

export interface CheckoutData {
  planName: string;
  price: number;
  cycle: 'monthly' | 'yearly';
}

interface AppRouterProps {
  user: User | null;
  history: AnalysisResult[];
  smcLibrary: SMCContent[];
  analysisData: AnalysisResult | null;
  isAnalyzing: boolean;
  checkoutData: CheckoutData | null;
  onNavigate: (view: ViewKey) => void;
  onLogin: (user: User) => void;
  onAnalyze: (url: string) => void;
  onDeductCredits: (amount: number) => boolean;
  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
  onAddToLibrary: (item: SMCContent) => void;
  onSelectAnalysis: (analysis: AnalysisResult) => void;
  onNewAnalysis: () => void;
  onConfirmSubscription: () => void;
  onFinishPaymentFlow: () => void;
  onLogout: () => void;
  onUpdateUser: (updates: Partial<User>) => void;
  notify: (type: 'success' | 'error' | 'info', message: string) => void;
  onOpenOrder: (orderId: string) => void;
}

const RequireAuth: React.FC<{ user: User | null; children: React.ReactNode }> = ({ user, children }) => {
  if (!user) {
    return <Navigate to={VIEWS.LOGIN} replace />;
  }
  return <>{children}</>;
};

const RequireAgency: React.FC<{ user: User | null; children: React.ReactNode }> = ({ user, children }) => {
  if (!user) {
    return <Navigate to={VIEWS.LOGIN} replace />;
  }
  if (user.plan !== 'agency') {
    return <Navigate to={VIEWS.DASHBOARD} replace />;
  }
  return <>{children}</>;
};

const AppRouter: React.FC<AppRouterProps> = ({
  user,
  history,
  smcLibrary,
  analysisData,
  isAnalyzing,
  checkoutData,
  onNavigate,
  onLogin,
  onAnalyze,
  onDeductCredits,
  onSaveSolution,
  onAddToLibrary,
  onSelectAnalysis,
  onNewAnalysis,
  onConfirmSubscription,
  onFinishPaymentFlow,
  onLogout,
  onUpdateUser,
  notify,
  onOpenOrder
}) => {
  const knowledgeTarget = analysisData || history[0];

  const AgencyOrderRoute: React.FC = () => {
    const { orderId } = useParams<{ orderId: string }>();
    if (!orderId) {
      return <Navigate to={VIEWS.AGENCY_ORDERS} replace />;
    }
    return <OrderDetailPage orderId={orderId} onBack={() => onNavigate(VIEWS.AGENCY_ORDERS)} />;
  };

  return (
    <div className="flex-1 min-h-0">
      <Routes>
        <Route
          path={VIEWS.HOME}
          element={<Home onNavigate={onNavigate} user={user} onAnalyze={onAnalyze} isAnalyzing={isAnalyzing} />}
        />
        <Route
          path={VIEWS.LOGIN}
          element={user ? <Navigate to={user.credits === 0 ? VIEWS.BILLING_CREDITS : VIEWS.ANALYZE} replace /> : <Login onLogin={onLogin} onBack={() => onNavigate(VIEWS.HOME)} />}
        />

        <Route
          path={VIEWS.DASHBOARD}
          element={(
            <RequireAuth user={user}>
              <Dashboard
                history={history}
                onView={(res) => { onSelectAnalysis(res); onNavigate(VIEWS.PROJECTS); }}
                onNavigate={onNavigate}
              />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.ANALYZE}
          element={(
            <RequireAuth user={user}>
              <Analyze onAnalyze={onAnalyze} isAnalyzing={isAnalyzing} />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.PROJECTS}
          element={(
            <RequireAuth user={user}>
              <Projects
                history={history}
                user={user}
                onDeductCredits={onDeductCredits}
                onSaveSolution={onSaveSolution}
                onNavigateToRecharge={() => onNavigate(VIEWS.BILLING_CREDITS)}
                onNewAnalysis={onNewAnalysis}
                initialAnalysis={analysisData}
              />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.KNOWLEDGE}
          element={(
            <RequireAuth user={user}>
              {knowledgeTarget ? <KnowledgeExplorer analysis={knowledgeTarget} /> : <Navigate to={VIEWS.DASHBOARD} replace />}
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.BENCHMARK}
          element={(
            <RequireAuth user={user}>
              <Benchmark history={history} />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.SMC_STUDIO}
          element={(
            <RequireAuth user={user}>
              <SMCStudio
                user={user}
                analysisData={analysisData}
                onDeductCredits={onDeductCredits}
                library={smcLibrary}
                onAddToLibrary={(item) => { onAddToLibrary(item); notify('success', 'Contenu ajouté à la bibliothèque.'); }}
              />
            </RequireAuth>
          )}
        />

        <Route
          path={VIEWS.BILLING_DASHBOARD}
          element={(
            <RequireAuth user={user}>
              <BillingDashboard onNavigate={onNavigate} />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.BILLING_SUBSCRIPTION}
          element={(
            <RequireAuth user={user}>
              <SubscriptionPage onBack={() => onNavigate(VIEWS.BILLING_DASHBOARD)} />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.BILLING_INVOICES}
          element={(
            <RequireAuth user={user}>
              <InvoicesPage onBack={() => onNavigate(VIEWS.BILLING_DASHBOARD)} />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.BILLING_PAYOUTS}
          element={(
            <RequireAuth user={user}>
              <PayoutsPage onBack={() => onNavigate(VIEWS.BILLING_DASHBOARD)} />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.BILLING_CREDITS}
          element={(
            <RequireAuth user={user}>
              <CreditsPage onBack={() => onNavigate(VIEWS.BILLING_DASHBOARD)} />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.BILLING_METHODS}
          element={(
            <RequireAuth user={user}>
              <PaymentMethodsPage onBack={() => onNavigate(VIEWS.BILLING_DASHBOARD)} />
            </RequireAuth>
          )}
        />

        <Route
          path={VIEWS.PAYMENT}
          element={(
            <RequireAuth user={user}>
              {checkoutData ? (
                <Payment
                  planDetails={checkoutData}
                  onSuccess={onConfirmSubscription}
                  onBack={() => onNavigate(VIEWS.BILLING_DASHBOARD)}
                />
              ) : (
                <Navigate to={VIEWS.BILLING_DASHBOARD} replace />
              )}
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.PAYMENT_SUCCESS}
          element={(
            <RequireAuth user={user}>
              {checkoutData ? (
                <PaymentSuccess
                  planDetails={checkoutData}
                  user={user}
                  onContinue={onFinishPaymentFlow}
                />
              ) : (
                <Navigate to={VIEWS.BILLING_DASHBOARD} replace />
              )}
            </RequireAuth>
          )}
        />

        <Route
          path={VIEWS.ACCOUNT}
          element={(
            <RequireAuth user={user}>
              <Account
                user={user}
                onLogout={onLogout}
                onNavigate={onNavigate}
                onUpdateUser={onUpdateUser}
              />
            </RequireAuth>
          )}
        />

        <Route
          path={VIEWS.INDEXATION_DASHBOARD}
          element={(
            <RequireAuth user={user}>
              <IndexationDashboard
                user={user}
                onNavigate={onNavigate}
                history={history}
              />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.INDEXATION_ROBOTS}
          element={(
            <RequireAuth user={user}>
              <RobotsTxtAnalyzer
                onBack={() => onNavigate(VIEWS.INDEXATION_DASHBOARD)}
                history={history}
              />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.INDEXATION_LLMS}
          element={(
            <RequireAuth user={user}>
              <LlmsTxtGenerator
                onBack={() => onNavigate(VIEWS.INDEXATION_DASHBOARD)}
                user={user}
                history={history}
              />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.INDEXATION_META}
          element={(
            <RequireAuth user={user}>
              <AiMetaTagsGenerator
                onBack={() => onNavigate(VIEWS.INDEXATION_DASHBOARD)}
                user={user}
                history={history}
              />
            </RequireAuth>
          )}
        />
        <Route
          path={VIEWS.INDEXATION_SIM}
          element={(
            <RequireAuth user={user}>
              <BotSimulator
                onBack={() => onNavigate(VIEWS.INDEXATION_DASHBOARD)}
                onDeductCredits={onDeductCredits}
              />
            </RequireAuth>
          )}
        />

        <Route
          path={VIEWS.AGENCY_ORDERS}
          element={(
            <RequireAgency user={user}>
              <OrdersListPage onNavigateToOrder={onOpenOrder} />
            </RequireAgency>
          )}
        />
        <Route
          path={VIEWS.AGENCY_ORDER_DETAIL}
          element={(
            <RequireAgency user={user}>
              <AgencyOrderRoute />
            </RequireAgency>
          )}
        />
        <Route
          path={VIEWS.AGENCY_STATS}
          element={(
            <RequireAgency user={user}>
              <OrdersStatsPage />
            </RequireAgency>
          )}
        />
        <Route
          path={VIEWS.AGENCY_SERVICES}
          element={(
            <RequireAgency user={user}>
              <AgencyServicesPage />
            </RequireAgency>
          )}
        />
        <Route
          path={VIEWS.AGENCY_PROFILE}
          element={(
            <RequireAgency user={user}>
              <AgencyProfilePage />
            </RequireAgency>
          )}
        />

        <Route path="*" element={<Navigate to={VIEWS.HOME} replace />} />
      </Routes>
    </div>
  );
};

export default AppRouter;

﻿import React from 'react';
import {
  LayoutDashboard,
  FolderOpen,
  Sparkles,
  Fuel,
  Network,
  BarChart3,
  CreditCard,
  Plus,
  Settings,
  HelpCircle,
  ChevronDown,
  MessageSquare,
  Home as HomeIcon,
  Search,
  Bot,
  FileText,
  FileCode,
  Code,
  Briefcase,
  Package,
  UserCheck
} from 'lucide-react';
import { AnalysisResult, User } from '../types';
import { ViewKey, VIEWS } from '../config/constants';
import { safeHostname } from '../utils/validation';

interface SidebarProps {
  currentView: ViewKey;
  user: User | null;
  history: AnalysisResult[];
  isMobileMenuOpen: boolean;
  onCloseMobileMenu: () => void;
  onNavigate: (view: ViewKey) => void;
  onSelectHistory: (analysis: AnalysisResult) => void;
}

type SidebarItemProps = {
  label: string;
  icon: React.ComponentType<{ size?: number | string; className?: string }>;
  onClick: () => void;
  isAction?: boolean;
  active?: boolean;
};

const SidebarItem: React.FC<SidebarItemProps> = ({ label, icon: Icon, onClick, isAction = false, active = false }) => {
  if (isAction) {
    return (
      <button
        onClick={onClick}
        className="w-full flex items-center gap-3 px-4 py-3 bg-surface-container hover:bg-surface-container-high text-primary rounded-2xl transition-all mb-4 group shadow-sm"
      >
        <Icon size={20} />
        <span className="font-medium text-sm">{label}</span>
      </button>
    );
  }

  return (
    <button
      onClick={onClick}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-full text-sm font-medium transition-all mb-1 ${
        active ? 'bg-primary-container text-on-primary-container' : 'text-secondary hover:bg-surface-container'
      }`}
    >
      <Icon size={20} className={active ? 'text-on-primary-container' : 'text-secondary'} />
      <span className="truncate">{label}</span>
    </button>
  );
};

const Sidebar: React.FC<SidebarProps> = ({
  currentView,
  user,
  history,
  isMobileMenuOpen,
  onCloseMobileMenu,
  onNavigate,
  onSelectHistory
}) => {
  const isActive = (id: ViewKey) => {
    if (id === VIEWS.HOME) return currentView === VIEWS.HOME;
    return currentView === id || currentView.startsWith(`${id}/`);
  };

  const SidebarHistoryItem: React.FC<{ result: AnalysisResult }> = ({ result }) => {
    const hostname = safeHostname(result.url) || result.url;
    return (
      <button
        onClick={() => onSelectHistory(result)}
        className="w-full text-left px-4 py-2 rounded-full text-xs text-secondary hover:text-white hover:bg-surface-container truncate transition-all mb-0.5 flex items-center gap-3"
      >
        <MessageSquare size={14} className="shrink-0 opacity-50" />
        <span className="truncate">{hostname}</span>
      </button>
    );
  };

  return (
    <>
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-black/50 z-40 md:hidden" onClick={onCloseMobileMenu}></div>
      )}

      <aside
        className={`
          fixed md:static inset-y-0 left-0 z-50 w-[280px] bg-surface-container/50 flex flex-col border-r border-outline/20 transition-transform duration-300 transform 
          ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
        `}
      >
        <div className="h-16 flex items-center px-6 shrink-0">
          <button onClick={() => onNavigate(VIEWS.HOME)} className="flex items-center gap-2 group">
            <span className="text-xl font-medium tracking-tight text-[#e3e3e3] group-hover:text-primary transition-colors">CitedBy<span className="text-primary">.ai</span></span>
            <ChevronDown size={14} className="text-gray-500 mt-1" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar px-3 py-2">
