                  {user.name.charAt(0)}
                </div>
                <div className="flex-1 min-w-0">
                  <div className="text-sm font-medium text-white truncate">{user.name}</div>
                  <div className="text-[10px] text-gray-400 truncate">{user.plan.toUpperCase()}</div>
