                <Settings size={16} className="text-gray-500" />
              </button>
            </div>
          ) : (
            <button onClick={() => onNavigate(VIEWS.LOGIN)} className="w-full py-2 bg-primary text-on-primary font-bold rounded-full hover:bg-primary/90 transition-colors text-sm">
              Connexion
            </button>
          )}
          <div className="flex justify-between items-center mt-3 px-2">
            <button onClick={() => onNavigate(VIEWS.BILLING_DASHBOARD)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1"><CreditCard size={12}/> Plans & Factures</button>
            <button className="text-xs text-gray-500 hover:text-white flex items-center gap-1"><HelpCircle size={12}/> Aide</button>
          </div>
        </div>
      </aside>
    </>
  );
};

export default Sidebar;

