import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import { GoogleGenAI, Type } from '@google/genai';
import { buildPrompt, MASTER_CONTEXT } from '../services/expert-prompts';
import { sanitizePromptText, normalizeUrl, isValidUrl, safeHostname } from '../utils/validation';
import type { Recommendation } from '../types';

dotenv.config({ path: '.env.local' });
dotenv.config();

const app = express();
app.use(cors({ origin: true }));
app.use(express.json({ limit: '1mb' }));

const port = Number(process.env.PORT || 8787);

const resolveCategoryKey = (category: string): string => {
  if (category.includes('Sémantique')) return 'semantic';
  if (category.includes('Contenu')) return 'content';
  if (category.includes('Autorité')) return 'entity';
  if (category.includes('Données')) return 'structured_data';
  if (category.includes('GEO')) return 'geo';
  if (category.includes('Confiance')) return 'trust';
  if (category.includes('Fraîcheur')) return 'freshness';
  return 'technical';
};

const getApiKey = (): string => {
  return process.env.GEMINI_API_KEY || '';
};

app.post('/api/generate-solution', async (req, res) => {
  const body = req.body ?? {};
  const rec = body.rec as Recommendation | undefined;
  const url = typeof body.url === 'string' ? body.url : '';

  if (!rec || typeof rec !== 'object') {
    return res.status(400).json({ error: 'Recommandation manquante.' });
  }

  const normalizedUrl = normalizeUrl(url);
  if (!isValidUrl(normalizedUrl)) {
    return res.status(400).json({ error: 'URL invalide pour la génération.' });
  }

  const apiKey = getApiKey();
  if (!apiKey) {
    return res.status(500).json({ error: 'Clé API Gemini absente. Configurez GEMINI_API_KEY.' });
  }

  const safeDomain = safeHostname(normalizedUrl) || 'inconnu';
  const safeCategory = sanitizePromptText(rec.category || '');
  const context = {
    url: sanitizePromptText(normalizedUrl),
    domain: sanitizePromptText(safeDomain),
    html: sanitizePromptText('<html><body>Extrait HTML simulé pour le contexte...</body></html>'),
    score: 65,
    categoryScore: 50,
    recTitle: sanitizePromptText(rec.title || ''),
    recDescription: sanitizePromptText(rec.description || ''),
    recAction: sanitizePromptText(rec.action || ''),
    recPriority: sanitizePromptText(rec.priority || ''),
    recImpact: sanitizePromptText(rec.impact || '')
  };

  const categoryKey = resolveCategoryKey(safeCategory);
  const userPrompt = buildPrompt(categoryKey, context);

  try {
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userPrompt,
      config: {
        systemInstruction: MASTER_CONTEXT,
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: {
              type: Type.STRING,
              description: "Le titre de la solution générée."
            },
            explanation: {
              type: Type.STRING,
              description: "Pourquoi cette solution aide à la citation par l'IA."
            },
            type: {
              type: Type.STRING,
              description: "Type de contenu: 'code' ou 'text'."
            },
            language: {
              type: Type.STRING,
              description: "Langage du code (html, json, markdown)."
            },
            content: {
              type: Type.STRING,
              description: "Le code ou texte d'optimisation généré."
            },
            implementationSteps: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Liste des étapes pour installer la solution."
            },
            estimatedImpact: {
              type: Type.STRING,
              description: "Impact estimé sur le score AEO."
            }
          },
          required: ['title', 'explanation', 'type', 'content', 'implementationSteps', 'estimatedImpact']
        }
      }
    });

    const text = response.text;
    if (!text) {
      return res.status(502).json({ error: 'Réponse vide de Gemini.' });
    }

    return res.json(JSON.parse(text));
  } catch (error) {
    console.error('Erreur Gemini /api/generate-solution:', error);
    return res.status(500).json({ error: 'Erreur lors de la génération Gemini.' });
  }
});

app.post('/api/generate-content', async (req, res) => {
  const prompt = typeof req.body?.prompt === 'string' ? req.body.prompt : '';
  const safePrompt = sanitizePromptText(prompt, 20000);

  if (!safePrompt) {
    return res.status(400).json({ error: 'Prompt manquant.' });
  }

  const apiKey = getApiKey();
  if (!apiKey) {
    return res.status(500).json({ error: 'Clé API Gemini absente. Configurez GEMINI_API_KEY.' });
  }

  try {
    const ai = new GoogleGenAI({ apiKey });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: safePrompt,
      config: {
        systemInstruction: MASTER_CONTEXT
      }
    });

    return res.json({ text: response.text || '' });
  } catch (error) {
    console.error('Erreur Gemini /api/generate-content:', error);
    return res.status(500).json({ error: 'Erreur lors de la génération Gemini.' });
  }
});

app.listen(port, () => {
  console.log(`Serveur API Gemini démarré sur http://localhost:${port}`);
});

