     2→import { AnalysisResult, CategoryScore, Recommendation, GraphNode, GraphLink } from '../types';
     3→import { CRITERIA_REPOSITORY, CATEGORY_NAMES } from './criteria';
     4→
     5→const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));
     6→
     7→export const analyzeUrl = async (url: string): Promise<AnalysisResult> => {
     8→  await delay(2000); // Simulation
     9→
    10→  const seed = url.length;
    11→  const domain = new URL(url).hostname;
    12→  
    13→  // Fonction utilitaire pour générer des scores pseudo-aléatoires stables
    14→  const getScore = (base: number, variance: number) => Math.min(100, Math.max(0, base + (seed % variance) - (variance/2)));
    15→
    16→  // Définition des 6 Piliers AEO/GEO exacts demandés
    17→  const categories: Record<string, CategoryScore> = {
    18→    structure: {
    19→      name: "Structure HTML & SEO",
    20→      score: getScore(85, 10),
    21→      weight: 15,
    22→      items: [
    23→        { status: 'success', message: "Hiérarchie H1-H6 logique pour les parsers" },
    24→        { status: 'success', message: "Balises sémantiques <article> présentes" },
    25→        { status: 'warning', message: "Table of Contents (ToC) manquante pour le contexte long" },
    26→        { status: 'error', message: "Absence de listes à puces pour les résumés IA" },
    27→        { status: 'success', message: "Attributs Alt descriptifs sur les images" }
    28→      ]
    29→    },
    30→    citability: {
    31→      name: "Citabilité IA",
    32→      score: getScore(55, 20), // Souvent bas par défaut
    33→      weight: 25,
    34→      items: [
    35→        { status: 'error', message: "Contenu non structuré en 'Answer-First'" },
    36→        { status: 'warning', message: "Pas de définitions claires en début de paragraphe" },
    37→        { status: 'error', message: "Absence de section FAQ structurée" },
    38→        { status: 'success', message: "Score de lisibilité Flesch-Kincaid adéquat" },
    39→        { status: 'warning', message: "Densité de connecteurs logiques faible" }
    40→      ]
    41→    },
    42→    authority: {
    43→      name: "Autorité & E-E-A-T",
    44→      score: getScore(75, 15),
    45→      weight: 20,
    46→      items: [
    47→        { status: 'success', message: "Page 'À propos' identifiée par le Knowledge Graph" },
    48→        { status: 'warning', message: "Auteurs non liés à leurs profils LinkedIn/Twitter" },
    49→        { status: 'error', message: "Manque de citations externes vers des sources d'autorité" },
    50→        { status: 'success', message: "HTTPS et certificats de sécurité valides" },
    51→        { status: 'success', message: "Mentions légales accessibles" }
    52→      ]
    53→    },
    54→    freshness: {
    55→      name: "Fraîcheur du contenu",
    56→      score: getScore(65, 20),
    57→      weight: 10,
    58→      items: [
    59→        { status: 'warning', message: "Date de dernière modification > 6 mois" },
    60→        { status: 'error', message: "Statistiques citées datant de plus de 2 ans" },
    61→        { status: 'success', message: "Sitemap.xml à jour" },
    62→        { status: 'warning', message: "Fréquence de publication faible détectée" }
    63→      ]
    64→    },
    65→    technical: {
    66→      name: "SEO Technique",
    67→      score: getScore(80, 10),
    68→      weight: 15,
    69→      items: [
    70→        { status: 'success', message: "Core Web Vitals (LCP, CLS) performants" },
    71→        { status: 'success', message: "Rendu Javascript compatible Crawl Budget" },
    72→        { status: 'warning', message: "Profondeur de clic > 3 pour certaines pages clés" },
    73→        { status: 'success', message: "Mobile-friendly (Critique pour Index Mobile)" },
    74→        { status: 'success', message: "Robots.txt bien configuré" },
    75→        { status: 'error', message: "Pas de balise 'last-modified' dans le header HTTP" }
    76→      ]
    77→    },
    78→    geo: {
    79→      name: "Optimisation GEO",
    80→      score: getScore(45, 15),
    81→      weight: 15,
    82→      items: [
    83→        { status: 'error', message: "Absence de Schema.org 'Organization' complet" },
    84→        { status: 'error', message: "Pas de microdonnées sur les entités nommées" },
    85→        { status: 'warning', message: "Structure de données JSON-LD incomplète" },
    86→        { status: 'success', message: "Open Graph Protocol détecté" },
    87→        { status: 'error', message: "Pas de liaison SameAs vers les bases de connaissances" }
    88→      ]
    89→    }
    90→  };
    91→
    92→  // Calcul du score global pondéré
    93→  let totalScore = 0;
    94→  let totalWeight = 0;
    95→  Object.values(categories).forEach(cat => {
    96→    totalScore += cat.score * cat.weight;
    97→    totalWeight += cat.weight;
    98→  });
    99→  const globalScore = Math.round(totalScore / totalWeight);
   100→
   101→  // Génération des recommandations basées sur les items en erreur/warning
   102→  const recommendations: Recommendation[] = [];
   103→  
   104→  Object.entries(categories).forEach(([key, cat]) => {
