import React, { useEffect, useRef } from 'react';
import { GeneratedSolution } from '../types';
import { X, Sparkles, Loader2, Copy, Download, ClipboardList } from 'lucide-react';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  isLoading: boolean;
  solution: GeneratedSolution | null;
}

const GenerationModal: React.FC<Props> = ({ isOpen, onClose, isLoading, solution }) => {
  if (!isOpen) return null;
  const modalRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!isOpen || !modalRef.current) return;

    const focusable = modalRef.current.querySelectorAll<HTMLElement>(
      'button, [href], input, select, textarea, [tabindex]:not([tabindex=\"-1\"])'
    );
    const first = focusable[0];
    const last = focusable[focusable.length - 1];

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        onClose();
        return;
      }
      if (event.key !== 'Tab' || focusable.length === 0) return;
      if (event.shiftKey && document.activeElement === first) {
        event.preventDefault();
        last?.focus();
      } else if (!event.shiftKey && document.activeElement === last) {
        event.preventDefault();
        first?.focus();
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    first?.focus();

    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, onClose]);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={onClose}></div>
      <div
        ref={modalRef}
        role="dialog"
        aria-modal="true"
        aria-labelledby="generation-modal-title"
        className="relative bg-surface border border-white/10 rounded-2xl w-full max-w-4xl max-h-[85vh] overflow-hidden flex flex-col shadow-2xl animate-in zoom-in duration-200"
      >
        <div className="p-6 border-b border-white/10 flex items-center justify-between bg-white/5">
          <div className="flex items-center gap-3">
            <Sparkles className="text-primary" size={24} />
            <h3 id="generation-modal-title" className="text-xl font-serif font-bold">{isLoading ? 'Génération AEO...' : solution?.title}</h3>
          </div>
          <button onClick={onClose} className="p-2 text-gray-400 hover:text-white" aria-label="Fermer"><X size={20} /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-8">
          {isLoading ? (
            <div className="flex flex-col items-center justify-center py-20 gap-4">
              <Loader2 className="animate-spin text-primary" size={48} />
              <p className="text-gray-400 animate-pulse">L'IA de CitedBy.ai rédige votre code d'optimisation...</p>
            </div>
          ) : solution && (
            <div className="grid md:grid-cols-12 gap-10">
              <div className="md:col-span-7 space-y-6">
                <div className="p-4 bg-primary/5 border border-primary/10 rounded-xl">
                   <p className="text-sm text-primary/80 leading-relaxed"><span className="font-bold">Objectif citation :</span> {solution.explanation}</p>
                </div>
                <div className="relative">
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-[10px] uppercase font-bold text-gray-500 tracking-widest">{solution.language} code</span>
                    <button className="text-xs text-primary hover:underline flex items-center gap-1"><Copy size={12}/> Copier</button>
                  </div>
                  <pre className="bg-black border border-white/5 p-6 rounded-xl text-sm font-mono text-gray-300 overflow-x-auto">
                    {solution.content}
                  </pre>
                </div>
              </div>
              <div className="md:col-span-5 space-y-6 border-l border-white/5 pl-10">
                 <h4 className="font-bold flex items-center gap-2 text-primary"><ClipboardList size={18}/> Guide d'installation</h4>
                 <div className="space-y-6">
                    {solution.implementationSteps.map((step, i) => (
                      <div key={i} className="flex gap-4">
                        <div className="w-6 h-6 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-xs font-bold text-gray-500 shrink-0">{i+1}</div>
                        <p className="text-sm text-gray-400 leading-relaxed">{step}</p>
                      </div>
                    ))}
                 </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default GenerationModal;

