import { Recommendation, GeneratedSolution } from '../types';
import { sanitizePromptText, normalizeUrl, isValidUrl, safeHostname } from '../utils/validation';

const buildFallbackSolution = (rec: Recommendation, url: string): GeneratedSolution => {
  const safeDomain = safeHostname(url) || 'exemple.com';
  return {
    title: `Optimisation : ${rec.title}`,
    explanation: "Cette solution structure vos données pour faciliter l'extraction d'entités par les LLMs.",
    type: 'code',
    language: 'html',
    content: `<!-- Script AEO automatique (Fallback) -->\n<script type="application/ld+json">\n{\n  "@context": "https://schema.org",\n  "@type": "WebPage",\n  "mainEntity": {\n    "@type": "Organization",\n    "name": "${safeDomain}"\n  }\n}\n</script>`,
    implementationSteps: [
      "Ouvrez le fichier template de votre page",
      "Insérez le script dans la balise <head>",
      "Validez avec l'outil d'inspection de schémas"
    ]
  };
};

export const generateSolution = async (rec: Recommendation, url: string): Promise<GeneratedSolution> => {
  const normalizedUrl = normalizeUrl(url);
  if (!isValidUrl(normalizedUrl)) {
    throw new Error("URL invalide pour la génération.");
  }

  const safeRec: Recommendation = {
    ...rec,
    title: sanitizePromptText(rec.title),
    description: sanitizePromptText(rec.description),
    action: sanitizePromptText(rec.action),
    category: sanitizePromptText(rec.category)
  };

  try {
    const response = await fetch('/api/generate-solution', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        rec: safeRec,
        url: normalizedUrl
      })
    });

    if (!response.ok) {
      const errorPayload = await response.json().catch(() => null);
      const detail = errorPayload?.error || `Erreur serveur (${response.status}).`;
      throw new Error(detail);
    }

    const data = await response.json();
    return data as GeneratedSolution;
  } catch (e) {
    console.error("Erreur Gemini Generator:", e);
    return buildFallbackSolution(rec, normalizedUrl);
  }
};

import React, { useMemo, useState, useEffect } from 'react';
import { AnalysisResult } from '../types';
import { ViewKey, VIEWS } from '../config/constants';
import { Plus, Activity, Fuel, TrendingUp, Clock, ChevronRight, BarChart3, Bot, Zap, Globe, ChevronDown, FolderOpen } from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';

interface Props {
  history: AnalysisResult[];
  onView: (analysis: AnalysisResult) => void;
  onNavigate: (view: ViewKey) => void;
}

const Dashboard: React.FC<Props> = ({ history, onView, onNavigate }) => {
  const uniqueUrls = useMemo(() => {
    return Array.from(new Set(history.map(h => h.url)));
  }, [history]);

  const [selectedUrl, setSelectedUrl] = useState<string>('');

  useEffect(() => {
    if (uniqueUrls.length > 0 && !selectedUrl) {
      setSelectedUrl(uniqueUrls[0]);
    }
  }, [uniqueUrls, selectedUrl]);

  const projectHistory = useMemo(() => {
    if (!selectedUrl) return [];
    return history
      .filter(h => h.url === selectedUrl)
      .sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
  }, [history, selectedUrl]);

  const currentScan = projectHistory.length > 0 ? projectHistory[projectHistory.length - 1] : null;
  const previousScan = projectHistory.length > 1 ? projectHistory[projectHistory.length - 2] : null;

  const chartData = useMemo(() => {
    return projectHistory.map(h => ({
      date: new Date(h.timestamp).toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit' }),
      score: h.globalScore,
      citation: h.aiCitation.probability
    }));
  }, [projectHistory]);

  const getTrend = (current: number, prev: number | undefined) => {
    if (prev === undefined) return { label: 'Initial', color: 'text-secondary' };
    const diff = current - prev;
    if (diff > 0) return { label: `+${diff}%`, color: 'text-primary' };
    if (diff < 0) return { label: `${diff}%`, color: 'text-red-400' };
    return { label: 'Stable', color: 'text-secondary' };
  };

  const scoreTrend = currentScan ? getTrend(currentScan.globalScore, previousScan?.globalScore) : { label: '-', color: '' };
  const citationTrend = currentScan ? getTrend(currentScan.aiCitation.probability, previousScan?.aiCitation.probability) : { label: '-', color: '' };

  if (history.length === 0) {
    return (
      <div className="max-w-6xl mx-auto px-6 py-20 text-center animate-in fade-in duration-500">
