                          dy={10}
                        />
                        <YAxis hide domain={[0, 100]} />
                        <Tooltip 
                          contentStyle={{ backgroundColor: '#1e1f20', border: '1px solid #444746', borderRadius: '8px', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                          itemStyle={{ fontSize: '12px', fontWeight: 'bold' }}
                          labelStyle={{ color: '#c4c7c5', marginBottom: '8px', fontSize: '10px' }}
                        />
                        <Area 
                          type="monotone" 
                          dataKey="score" 
                          stroke="#a8c7fa" 
                          strokeWidth={3} 
                          fill="url(#colorScore)" 
                          activeDot={{ r: 6, strokeWidth: 0, fill: '#a8c7fa' }}
                        />
                        <Area 
