                      <div key={i} className="flex gap-4 relative">
                         <div className="flex flex-col items-center">
                            <div className={`w-2 h-2 rounded-full ${feed.color} shadow-sm z-10`}></div>
                            {i !== 3 && <div className="w-px h-full bg-outline/20 absolute top-2 bottom-0 -mb-5"></div>}
                         </div>
                         <div className="pb-2">
                            <p className="text-xs font-bold text-gray-200">{feed.msg}</p>
                            <p className="text-[10px] text-secondary mt-1 uppercase tracking-wider font-bold">{feed.time}</p>
                         </div>
                      </div>
                    ))}
                 </div>
                 <button onClick={() => onView(currentScan)} className="mt-4 w-full py-3 bg-surface-container hover:bg-surface-container-high rounded-full text-xs font-bold text-secondary transition-all">
                    Voir le rapport détaillé
                 </button>
               </div>
            </div>
          </div>
        </>
      ) : (
        <div className="flex flex-col items-center justify-center h-64 text-secondary glass-panel rounded-2xl border-dashed border-outline/30">
           <Activity size={32} className="mb-2 opacity-50"/>
           <p className="text-sm">Sélectionnez ou analysez un projet pour voir les données.</p>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

