﻿export const MAX_PROMPT_LENGTH = 2000;

const CONTROL_CHARS = /[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g;

export const sanitizePromptText = (input: string, maxLength: number = MAX_PROMPT_LENGTH): string => {
  if (!input) return '';
  const cleaned = input.replace(CONTROL_CHARS, '').trim();
  return cleaned.length > maxLength ? cleaned.slice(0, maxLength) : cleaned;
};

export const normalizeUrl = (input: string): string => {
  const trimmed = input.trim();
  if (!trimmed) return '';
  if (/^https?:\/\//i.test(trimmed)) return trimmed;
  return `https://${trimmed}`;
};

export const isValidUrl = (input: string): boolean => {
  if (!input) return false;
  try {
    const url = new URL(input);
    return url.protocol === 'http:' || url.protocol === 'https:';
  } catch {
    return false;
  }
};

export const safeHostname = (input: string): string => {
  const normalized = normalizeUrl(input);
  if (!isValidUrl(normalized)) return '';
  try {
    return new URL(normalized).hostname;
  } catch {
    return '';
  }
};

export const isValidEmail = (input: string): boolean => {
  if (!input) return false;
  // Validation pragmatique pour l'UI, sans bloquer les emails standards.
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(input.trim());
};

