import React from 'react';
import { Recommendation, GeneratedSolution } from '../types';
import { Zap, Clock, TrendingUp, CheckCircle2, Eye, ArrowRight, Fuel } from 'lucide-react';

interface Props {
  rec: Recommendation;
  cost: number;
  onApply: (rec: Recommendation) => void;
  existingSolution?: GeneratedSolution;
  onView: (solution: GeneratedSolution) => void;
}

const RecommendationCard: React.FC<Props> = ({ rec, cost, onApply, existingSolution, onView }) => {
  const isCritical = rec.priority === 'critical';

  // Style configurations based on priority (matching the image)
  const styles = isCritical 
    ? {
        wrapper: 'bg-[#180505] border-red-500/20 hover:border-red-500/40',
        badge: 'bg-red-600 text-white',
        text: 'text-red-500',
        impactDot: 'bg-[#10b981]', // Green dots as per image
        impactDotEmpty: 'bg-[#1e293b]'
      }
    : {
        wrapper: 'bg-[#180e05] border-orange-500/20 hover:border-orange-500/40',
        badge: 'bg-orange-500 text-white',
        text: 'text-orange-500',
        impactDot: 'bg-[#10b981]',
        impactDotEmpty: 'bg-[#1e293b]'
      };

  // Convert impact string 'High'/'Medium'/'Low' to a number 1-5 for the dots
  const getImpactScore = (impact: string) => {
    switch(impact.toLowerCase()) {
      case 'high': return 5;
      case 'medium': return 3;
      default: return 1;
    }
  };

  const impactScore = getImpactScore(rec.impact);

  return (
    <div className={`p-6 rounded-2xl border transition-all group relative flex flex-col h-full ${styles.wrapper}`}>

      {/* Header: Badges & Impact */}
      <div className="flex justify-between items-start mb-4">
        <div className="flex items-center gap-3">
          {/* Priority Badge */}
          <span className={`px-2.5 py-1 rounded-md text-[10px] font-bold uppercase tracking-wider ${styles.badge}`}>
            {rec.priority}
          </span>
          {/* Category Badge */}
          <span className="px-2.5 py-1 rounded-md bg-[#27272a] text-gray-400 text-[10px] font-bold uppercase tracking-wider border border-white/5">
            {rec.category}
          </span>
        </div>

        {/* Impact Dots */}
        <div className="flex items-center gap-2">
            <span className="text-[10px] text-gray-500 uppercase font-bold tracking-wider mr-1">Impact:</span>
            <div className="flex gap-1">
                {[1, 2, 3, 4, 5].map((dot) => (
                    <div 
                        key={dot} 
                        className={`w-2 h-2 rounded-full ${dot <= impactScore ? styles.impactDot : styles.impactDotEmpty}`}
                    ></div>
                ))}
            </div>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1">
        <h3 className="text-lg font-bold text-white mb-3 font-sans">{rec.title}</h3>
        <p className="text-sm text-gray-400 leading-relaxed mb-6">
            {rec.description}
        </p>
      </div>

      {/* Footer: Effort & Action */}
      <div className="flex items-center justify-between pt-6 mt-auto">
        <div className="flex items-center gap-2 text-xs text-gray-500 font-medium">
           <Clock size={14} />
           <span>Effort: {rec.effort === 'low' ? '1-2h' : rec.effort === 'medium' ? '2-3h' : '4-6h'}</span>
        </div>

        <button 
          onClick={() => existingSolution ? onView(existingSolution) : onApply(rec)}
          className={`flex items-center gap-2 text-sm font-bold transition-all hover:opacity-80 py-2 px-3 rounded-lg ${existingSolution ? 'bg-white/5 text-gray-300' : 'bg-white/5 ' + styles.text}`}
        >
          {existingSolution ? (
            <>
              <Eye size={16} /> Voir Solution
            </>
          ) : (
            <>
              <Fuel size={14} />
              <span>
                 {rec.action.split(':')[0] || 'Optimiser'} 
                 <span className="ml-1 opacity-70 text-xs">(-{cost})</span>
              </span>
              <ArrowRight size={16} />
            </>
          )}
        </button>
      </div>

      {existingSolution && (
        <div className="absolute top-4 right-4 text-emerald-500">
            <CheckCircle2 size={20} />
        </div>
      )}
    </div>
  );
};

export default RecommendationCard;

