﻿import React, { useState, useEffect, useCallback } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { User, AnalysisResult, SMCContent, GeneratedSolution, Notification, PlanTier } from './types';
import { analyzeUrl } from './services/analyzer';
import NotificationSystem from './components/NotificationSystem';
import Sidebar from './components/Sidebar';
import MobileHeader from './components/MobileHeader';
import AppRouter, { CheckoutData } from './components/AppRouter';
import ErrorBoundary from './components/ErrorBoundary';
import { buildAgencyOrderPath, CREDIT_COSTS, VIEWS, ViewKey } from './config/constants';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [history, setHistory] = useState<AnalysisResult[]>([]);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [checkoutData, setCheckoutData] = useState<CheckoutData | null>(null);
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    const savedHistory = localStorage.getItem('aeo_history_v2');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const savedLibrary = localStorage.getItem('aeo_library_v2');
    if (savedLibrary) setSmcLibrary(JSON.parse(savedLibrary));

    const savedUser = localStorage.getItem('aeo_user');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  useEffect(() => {
    localStorage.setItem('aeo_history_v2', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('aeo_library_v2', JSON.stringify(smcLibrary));
  }, [smcLibrary]);

  useEffect(() => {
    if (user) localStorage.setItem('aeo_user', JSON.stringify(user));
    else localStorage.removeItem('aeo_user');
  }, [user]);

  const notify = useCallback((type: 'success' | 'error' | 'info', message: string) => {
    const id = Date.now().toString();
    setNotifications(prev => [...prev, { id, type, message }]);
  }, []);

  const dismissNotification = useCallback((id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  }, []);

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    if (loggedInUser.credits === 0) {
      navigate(VIEWS.BILLING_CREDITS);
      notify('info', 'Bienvenue ! Veuillez recharger votre compte pour commencer à générer des solutions.');
    } else {
      navigate(VIEWS.ANALYZE);
      notify('success', `Bon retour, ${loggedInUser.name}`);
    }
  };

  const handleLogout = () => {
    setUser(null);
    navigate(VIEWS.HOME);
    notify('info', 'Déconnexion réussie.');
  };

  const handleUpdateUser = (updates: Partial<User>) => {
    if (user) {
      setUser({ ...user, ...updates });
    }
  };

  const handleDeductCredits = (amount: number): boolean => {
    if (!user) {
      navigate(VIEWS.LOGIN);
      notify('error', 'Veuillez vous connecter.');
      return false;
    }
    if (user.credits < amount) {
      notify('error', 'Crédits Gas insuffisants. Redirection vers la recharge.');
      navigate(VIEWS.BILLING_CREDITS);
      return false;
    }
    setUser({ ...user, credits: user.credits - amount });
    return true;
  };

  const handleAnalyze = async (url: string) => {
    if (isAnalyzing) return;
    if (!handleDeductCredits(CREDIT_COSTS.analysis)) return;

    setIsAnalyzing(true);
    try {
      const result = await analyzeUrl(url);
      setAnalysisData(result);
      setHistory(prev => [result, ...prev]);
      navigate(VIEWS.PROJECTS);
      notify('success', `Analyse terminée avec succès (-${CREDIT_COSTS.analysis} Gas).`);
    } catch (error) {
      console.error('Analysis failed', error);
      notify('error', "Erreur lors de l'analyse. Veuillez réessayer.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleConfirmSubscription = () => {
    if (!user || !checkoutData) return;
    let newPlan: PlanTier = 'starter';
    let addedCredits = 0;

    switch (checkoutData.planName) {
      case 'Starter': newPlan = 'starter'; addedCredits = 50; break;
      case 'Optimizer': newPlan = 'optimizer'; addedCredits = 500; break;
      case 'Agence': newPlan = 'agency'; addedCredits = 2000; break;
      default: newPlan = 'starter'; addedCredits = 50;
    }

    setUser({ ...user, plan: newPlan, credits: user.credits + addedCredits });
    navigate(VIEWS.PAYMENT_SUCCESS);
  };

  const handleFinishPaymentFlow = () => {
    setCheckoutData(null);
    navigate(VIEWS.BILLING_DASHBOARD);
  };

  const handleSaveSolution = useCallback((analysisId: string, recId: string, solution: GeneratedSolution) => {
    const timestamp = new Date().toISOString();
    const solutionWithMeta = { ...solution, timestamp };
    setHistory(prev => prev.map(item => {
      if (item.timestamp === analysisId) {
        return { ...item, generatedSolutions: { ...(item.generatedSolutions || {}), [recId]: solutionWithMeta } };
      }
      return item;
    }));
    notify('success', 'Solution sauvegardée dans le projet.');
  }, [notify]);

  const handleOpenOrder = (orderId: string) => {
    navigate(buildAgencyOrderPath(orderId));
  };

  const pathname = location.pathname;
  const isPaymentFlow = pathname.startsWith(VIEWS.PAYMENT);
  const isHome = pathname === VIEWS.HOME;
  const isLogin = pathname === VIEWS.LOGIN;

  const handleNavigate = useCallback((view: ViewKey) => {
    navigate(view);
  }, [navigate]);

  return (
    <div className="flex h-screen bg-background text-[#e3e3e3] font-sans overflow-hidden">
      <NotificationSystem notifications={notifications} onDismiss={dismissNotification} />

      {!isPaymentFlow && !isHome && !isLogin && (
        <Sidebar
          currentView={pathname as ViewKey}
          user={user}
          history={history}
          isMobileMenuOpen={isMobileMenuOpen}
          onCloseMobileMenu={() => setIsMobileMenuOpen(false)}
          onNavigate={handleNavigate}
          onSelectHistory={(result) => { setAnalysisData(result); navigate(VIEWS.PROJECTS); }}
        />
      )}

      <main className="flex-1 overflow-y-auto relative bg-background flex flex-col">
        {!isPaymentFlow && !isHome && !isLogin && (
          <MobileHeader user={user} onOpenMenu={() => setIsMobileMenuOpen(true)} />
        )}

        <ErrorBoundary>
          <AppRouter
            user={user}
            history={history}
            smcLibrary={smcLibrary}
            analysisData={analysisData}
            isAnalyzing={isAnalyzing}
            checkoutData={checkoutData}
            onNavigate={handleNavigate}
            onLogin={handleLogin}
            onAnalyze={handleAnalyze}
            onDeductCredits={handleDeductCredits}
            onSaveSolution={handleSaveSolution}
            onAddToLibrary={(item) => setSmcLibrary(prev => [item, ...prev])}
            onSelectAnalysis={setAnalysisData}
            onNewAnalysis={() => navigate(VIEWS.ANALYZE)}
            onConfirmSubscription={handleConfirmSubscription}
            onFinishPaymentFlow={handleFinishPaymentFlow}
            onLogout={handleLogout}
            onUpdateUser={handleUpdateUser}
            notify={notify}
            onOpenOrder={handleOpenOrder}
          />
        </ErrorBoundary>
      </main>
    </div>
  );
};

export default App;

