import { AnalysisResult, CategoryScore, Recommendation, GraphNode, GraphLink } from '../types';
import { CRITERIA_REPOSITORY, CATEGORY_NAMES } from './criteria';

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const analyzeUrl = async (url: string): Promise<AnalysisResult> => {
  await delay(2000); // Simulation

  const seed = url.length;
  const domain = new URL(url).hostname;

  // Fonction utilitaire pour générer des scores pseudo-aléatoires stables
  const getScore = (base: number, variance: number) => Math.min(100, Math.max(0, base + (seed % variance) - (variance/2)));

  // Définition des 6 Piliers AEO/GEO exacts demandés
  const categories: Record<string, CategoryScore> = {
    structure: {
      name: "Structure HTML & SEO",
      score: getScore(85, 10),
      weight: 15,
      items: [
        { status: 'success', message: "Hiérarchie H1-H6 logique pour les parsers" },
        { status: 'success', message: "Balises sémantiques <article> présentes" },
        { status: 'warning', message: "Table of Contents (ToC) manquante pour le contexte long" },
        { status: 'error', message: "Absence de listes à puces pour les résumés IA" },
        { status: 'success', message: "Attributs Alt descriptifs sur les images" }
      ]
    },
    citability: {
      name: "Citabilité IA",
      score: getScore(55, 20), // Souvent bas par défaut
      weight: 25,
      items: [
        { status: 'error', message: "Contenu non structuré en 'Answer-First'" },
        { status: 'warning', message: "Pas de définitions claires en début de paragraphe" },
        { status: 'error', message: "Absence de section FAQ structurée" },
        { status: 'success', message: "Score de lisibilité Flesch-Kincaid adéquat" },
        { status: 'warning', message: "Densité de connecteurs logiques faible" }
      ]
    },
    authority: {
      name: "Autorité & E-E-A-T",
      score: getScore(75, 15),
      weight: 20,
      items: [
        { status: 'success', message: "Page 'À propos' identifiée par le Knowledge Graph" },
        { status: 'warning', message: "Auteurs non liés à leurs profils LinkedIn/Twitter" },
        { status: 'error', message: "Manque de citations externes vers des sources d'autorité" },
        { status: 'success', message: "HTTPS et certificats de sécurité valides" },
        { status: 'success', message: "Mentions légales accessibles" }
      ]
    },
    freshness: {
      name: "Fraîcheur du contenu",
      score: getScore(65, 20),
      weight: 10,
      items: [
        { status: 'warning', message: "Date de dernière modification > 6 mois" },
        { status: 'error', message: "Statistiques citées datant de plus de 2 ans" },
        { status: 'success', message: "Sitemap.xml à jour" },
        { status: 'warning', message: "Fréquence de publication faible détectée" }
      ]
    },
    technical: {
      name: "SEO Technique",
      score: getScore(80, 10),
      weight: 15,
      items: [
        { status: 'success', message: "Core Web Vitals (LCP, CLS) performants" },
        { status: 'success', message: "Rendu Javascript compatible Crawl Budget" },
        { status: 'warning', message: "Profondeur de clic > 3 pour certaines pages clés" },
        { status: 'success', message: "Mobile-friendly (Critique pour Index Mobile)" },
        { status: 'success', message: "Robots.txt bien configuré" },
        { status: 'error', message: "Pas de balise 'last-modified' dans le header HTTP" }
      ]
    },
    geo: {
      name: "Optimisation GEO",
      score: getScore(45, 15),
      weight: 15,
      items: [
        { status: 'error', message: "Absence de Schema.org 'Organization' complet" },
        { status: 'error', message: "Pas de microdonnées sur les entités nommées" },
        { status: 'warning', message: "Structure de données JSON-LD incomplète" },
        { status: 'success', message: "Open Graph Protocol détecté" },
        { status: 'error', message: "Pas de liaison SameAs vers les bases de connaissances" }
      ]
    }
  };

  // Calcul du score global pondéré
  let totalScore = 0;
  let totalWeight = 0;
  Object.values(categories).forEach(cat => {
    totalScore += cat.score * cat.weight;
    totalWeight += cat.weight;
  });
  const globalScore = Math.round(totalScore / totalWeight);

  // Génération des recommandations basées sur les items en erreur/warning
  const recommendations: Recommendation[] = [];

  Object.entries(categories).forEach(([key, cat]) => {
    cat.items.forEach((item, idx) => {
      if (item.status !== 'success') {
        recommendations.push({
          id: `rec-${key}-${idx}`,
          priority: item.status === 'error' ? 'critical' : 'high',
          category: CATEGORY_NAMES[key] || cat.name,
          title: item.message,
          description: `L'analyse a détecté une lacune : "${item.message}". Cela réduit la probabilité que votre contenu soit sélectionné par les moteurs de réponse (AEO).`,
          action: item.status === 'error' ? 'Implémenter' : 'Corriger',
          effort: idx % 2 === 0 ? 'medium' : 'low',
          impact: 'high'
        });
      }
    });
  });

  // Graph Data Mock (inchangé pour l'instant)
  const nodes: GraphNode[] = [
    { id: 'main', label: domain, type: 'entity', val: 20 },
    { id: 'k1', label: 'Sector Activity', type: 'keyword', val: 12 },
    { id: 's1', label: 'Industry Source', type: 'source', val: 8 },
  ];
  const links: GraphLink[] = [
    { source: 'main', target: 'k1', strength: 0.8 },
    { source: 'main', target: 's1', strength: 0.4 },
  ];

  return {
    url,
    timestamp: new Date().toISOString(),
    globalScore,
    categories,
    recommendations: recommendations.slice(0, 8), // Limiter pour la démo
    knowledgeGraph: { nodes, links },
    aiCitation: {
      probability: Math.round(globalScore * 0.4), // Probabilité plus sévère
      before: `Données non structurées, difficulté d'extraction pour les LLMs.`,
      after: `Entité structurée, citabilité maximale pour les requêtes complexes.`
    }
  };
};

