                    <Globe size={18} className="text-primary"/> 
                    Flux d'Activité
                 </h3>
                 <div className="flex-1 space-y-5 overflow-y-auto max-h-[300px] custom-scrollbar pr-2">
                    {[
                      { type: 'scan', msg: `Audit AEO complété`, time: 'À l\'instant', color: 'bg-primary' },
                      { type: 'idx', msg: 'Hausse du score technique', time: 'Il y a 2h', color: 'bg-blue-400' },
                      { type: 'cite', msg: 'Détection snippet Perplexity', time: 'Hier', color: 'bg-amber-400' },
                      { type: 'alert', msg: 'Données structurées manquantes', time: 'Hier', color: 'bg-red-400' },
                    ].map((feed, i) => (
                      <div key={i} className="flex gap-4 relative">
