};

app.post('/api/generate-solution', async (req, res) => {
  const body = req.body ?? {};
  const rec = body.rec as Recommendation | undefined;
  const url = typeof body.url === 'string' ? body.url : '';

  if (!rec || typeof rec !== 'object') {
    return res.status(400).json({ error: 'Recommandation manquante.' });
  }

  const normalizedUrl = normalizeUrl(url);
  if (!isValidUrl(normalizedUrl)) {
    return res.status(400).json({ error: 'URL invalide pour la génération.' });
  }

  const apiKey = getApiKey();
  if (!apiKey) {
    return res.status(500).json({ error: 'Clé API Gemini absente. Configurez GEMINI_API_KEY.' });
  }

