            explanation: {
              type: Type.STRING,
              description: "Pourquoi cette solution aide à la citation par l'IA."
            },
            type: {
              type: Type.STRING,
              description: "Type de contenu: 'code' ou 'text'."
            },
            language: {
              type: Type.STRING,
              description: "Langage du code (html, json, markdown)."
            },
            content: {
              type: Type.STRING,
              description: "Le code ou texte d'optimisation généré."
            },
            implementationSteps: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Liste des étapes pour installer la solution."
            },
            estimatedImpact: {
              type: Type.STRING,
              description: "Impact estimé sur le score AEO."
            }
          },
          required: ['title', 'explanation', 'type', 'content', 'implementationSteps', 'estimatedImpact']
        }
      }
    });

    const text = response.text;
    if (!text) {
      return res.status(502).json({ error: 'Réponse vide de Gemini.' });
    }

    return res.json(JSON.parse(text));
  } catch (error) {
    console.error('Erreur Gemini /api/generate-solution:', error);
    return res.status(500).json({ error: 'Erreur lors de la génération Gemini.' });
  }
});

