    19→      <li>Optimisation llms.txt</li>
    20→      <li>Robots.txt IA</li>
    21→    </ul>
    22→    <img src="/hero.png" />
    23→    <script type="application/ld+json">{ "@context": "https://schema.org", "@type": "Organization", "name": "MonSite" }</script>
    24→  </body>
    25→</html>`;
    26→
    27→  let html = '';
    28→  try {
    29→    const response = await fetch(`/api/fetch-page?url=${encodeURIComponent(url)}`);
    30→    if (response.ok) {
    31→      html = await response.text();
    32→    }
    33→  } catch {
    34→    // Fallback sur un HTML simule
    35→  }
    36→
    37→  const finalHtml = html || sampleHtml;
    38→  const extracted = extractBotVisibleContent(finalHtml);
    39→  const issues = [
    40→    extracted.imagesWithoutAlt > 0 ? 'Images sans attribut alt detectees.' : '',
    41→    extracted.structuredData ? '' : 'Aucune donnee structuree detectee.',
    42→    'Contenu charge en JavaScript (risque potentiel).'
    43→  ].filter(Boolean);
    44→
    45→  return {
    46→    html: finalHtml,
    47→    text: extracted.text,
    48→    entities: ['MonSite', 'Audit IA', 'Optimisation llms.txt'],
    49→    images: extracted.images,
    50→    imagesWithoutAlt: extracted.imagesWithoutAlt,
    51→    loadTime: '0.4s',
    52→    issues,
    53→    contentSummary: `Bot ${botType} a extrait ${extracted.text.split(' ').length} mots utiles.`,
    54→    extracted
    55→  };
    56→}
    57→
    58→export function extractBotVisibleContent(html: string): ExtractedContent {
    59→  const text = html
    60→    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    61→    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    62→    .replace(/<[^>]*>/g, ' ')
    63→    .replace(/\s+/g, ' ')
    64→    .trim();
    65→
    66→  const headings = Array.from(html.matchAll(/<h[1-6][^>]*>(.*?)<\/h[1-6]>/gi)).map(match => match[1]);
    67→  const images = (html.match(/<img\s/gi) || []).length;
    68→  const imagesWithoutAlt = (html.match(/<img(?![^>]*\salt=)[^>]*>/gi) || []).length;
    69→  const links = (html.match(/<a\s/gi) || []).length;
    70→  const structuredData = /application\/ld\+json/i.test(html);
    71→
    72→  return { text, headings, links, images, imagesWithoutAlt, structuredData };
    73→}
