    11→export async function fetchAndAnalyzeRobots(url: string): Promise<RobotsTxtAnalysis> {
    12→  const target = normalizeUrl(url);
    13→  if (!isValidUrl(target)) {
    14→    return {
    15→      raw: '',
    16→      exists: false,
    17→      botStatuses: {},
    18→      hasSitemap: false,
    19→      issues: ['URL invalide.'],
    20→      recommendations: ['Veuillez saisir une URL valide.']
    21→    };
    22→  }
    23→
    24→  await delay(400);
    25→
    26→  const robotsUrl = `${target.replace(/\/$/, '')}/robots.txt`;
    27→  try {
    28→    const response = await fetch(`/api/fetch-page?url=${encodeURIComponent(robotsUrl)}`, { method: 'GET' });
    29→    if (!response.ok) {
    30→      throw new Error('robots.txt introuvable');
    31→    }
    32→    const text = await response.text();
    33→    return parseRobotsTxt(text);
    34→  } catch {
    35→    const fallback = `User-agent: *\nDisallow:\n\n# Aucune regle specifique bots IA\n`;
    36→    return parseRobotsTxt(fallback);
    37→  }
    38→}
    39→
    40→export function parseRobotsTxt(content: string): RobotsTxtAnalysis {
    41→  const lines = content.split('\n').map(line => line.trim());
    42→  const rules: Record<string, { allow: string[]; disallow: string[] }> = {};
    43→  let currentAgent = '*';
    44→
    45→  for (const line of lines) {
    46→    if (!line || line.startsWith('#')) continue;
    47→    const [rawKey, rawValue] = line.split(':');
    48→    if (!rawKey || !rawValue) continue;
    49→    const key = rawKey.trim().toLowerCase();
    50→    const value = rawValue.trim();
    51→
    52→    if (key === 'user-agent') {
    53→      currentAgent = value;
    54→      if (!rules[currentAgent]) rules[currentAgent] = { allow: [], disallow: [] };
    55→    }
    56→    if (key === 'allow') {
    57→      if (!rules[currentAgent]) rules[currentAgent] = { allow: [], disallow: [] };
    58→      rules[currentAgent].allow.push(value);
    59→    }
    60→    if (key === 'disallow') {
    61→      if (!rules[currentAgent]) rules[currentAgent] = { allow: [], disallow: [] };
    62→      rules[currentAgent].disallow.push(value);
    63→    }
    64→  }
    65→
    66→  const botStatuses: Record<string, 'allowed' | 'blocked' | 'default'> = {};
    67→  const issues: string[] = [];
    68→  const recommendations: string[] = [];
    69→
    70→  AI_BOTS.forEach((bot) => {
    71→    const status = checkBotAccess(content, bot.userAgent);
    72→    botStatuses[bot.name] = status;
    73→    if (status === 'blocked') {
    74→      issues.push(`${bot.name} est bloque par robots.txt.`);
    75→    } else if (status === 'default') {
    76→      issues.push(`${bot.name} n a pas de regle explicite.`);
    77→    }
    78→  });
    79→
    80→  if (issues.length === 0) {
    81→    recommendations.push('Vos bots IA principaux sont autorises.');
    82→  } else {
    83→    recommendations.push('Ajoutez des directives explicites pour vos bots IA prioritaires.');
    84→  }
    85→
    86→  const sitemapLine = lines.find(line => line.toLowerCase().startsWith('sitemap:'));
    87→  const hasSitemap = Boolean(sitemapLine);
    88→  const sitemapUrl = sitemapLine ? sitemapLine.split(':').slice(1).join(':').trim() : undefined;
    89→
    90→  return {
    91→    raw: content,
    92→    exists: content.length > 0,
    93→    botStatuses,
    94→    hasSitemap,
    95→    sitemapUrl,
    96→    issues,
    97→    recommendations
    98→  };
    99→}
