     1→﻿export const MAX_PROMPT_LENGTH = 2000;
     2→
     3→const CONTROL_CHARS = /[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g;
     4→
     5→export const sanitizePromptText = (input: string, maxLength: number = MAX_PROMPT_LENGTH): string => {
     6→  if (!input) return '';
     7→  const cleaned = input.replace(CONTROL_CHARS, '').trim();
     8→  return cleaned.length > maxLength ? cleaned.slice(0, maxLength) : cleaned;
     9→};
    10→
    11→export const normalizeUrl = (input: string): string => {
    12→  const trimmed = input.trim();
    13→  if (!trimmed) return '';
    14→  if (/^https?:\/\//i.test(trimmed)) return trimmed;
    15→  return `https://${trimmed}`;
    16→};
    17→
    18→export const isValidUrl = (input: string): boolean => {
    19→  if (!input) return false;
    20→  try {
    21→    const url = new URL(input);
    22→    return url.protocol === 'http:' || url.protocol === 'https:';
    23→  } catch {
    24→    return false;
    25→  }
    26→};
    27→
    28→export const safeHostname = (input: string): string => {
    29→  const normalized = normalizeUrl(input);
    30→  if (!isValidUrl(normalized)) return '';
    31→  try {
    32→    return new URL(normalized).hostname;
    33→  } catch {
    34→    return '';
    35→  }
    36→};
    37→
    38→export const isValidEmail = (input: string): boolean => {
    39→  if (!input) return false;
    40→  // Validation pragmatique pour l'UI, sans bloquer les emails standards.
    41→  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(input.trim());
    42→};
