     2→import React, { useEffect, useRef } from 'react';
     3→import { GeneratedSolution } from '../types';
     4→import { X, Sparkles, Loader2, Copy, Download, ClipboardList } from 'lucide-react';
     5→
     6→interface Props {
     7→  isOpen: boolean;
     8→  onClose: () => void;
     9→  isLoading: boolean;
    10→  solution: GeneratedSolution | null;
    11→}
    12→
    13→const GenerationModal: React.FC<Props> = ({ isOpen, onClose, isLoading, solution }) => {
    14→  if (!isOpen) return null;
    15→  const modalRef = useRef<HTMLDivElement>(null);
    16→
    17→  useEffect(() => {
    18→    if (!isOpen || !modalRef.current) return;
    19→
    20→    const focusable = modalRef.current.querySelectorAll<HTMLElement>(
    21→      'button, [href], input, select, textarea, [tabindex]:not([tabindex=\"-1\"])'
    22→    );
    23→    const first = focusable[0];
    24→    const last = focusable[focusable.length - 1];
    25→
    26→    const handleKeyDown = (event: KeyboardEvent) => {
    27→      if (event.key === 'Escape') {
    28→        onClose();
    29→        return;
    30→      }
    31→      if (event.key !== 'Tab' || focusable.length === 0) return;
    32→      if (event.shiftKey && document.activeElement === first) {
    33→        event.preventDefault();
    34→        last?.focus();
    35→      } else if (!event.shiftKey && document.activeElement === last) {
    36→        event.preventDefault();
    37→        first?.focus();
    38→      }
    39→    };
    40→
    41→    document.addEventListener('keydown', handleKeyDown);
    42→    first?.focus();
    43→
    44→    return () => document.removeEventListener('keydown', handleKeyDown);
    45→  }, [isOpen, onClose]);
    46→
    47→  return (
    48→    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
    49→      <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={onClose}></div>
    50→      <div
    51→        ref={modalRef}
    52→        role="dialog"
    53→        aria-modal="true"
    54→        aria-labelledby="generation-modal-title"
    55→        className="relative bg-surface border border-white/10 rounded-2xl w-full max-w-4xl max-h-[85vh] overflow-hidden flex flex-col shadow-2xl animate-in zoom-in duration-200"
    56→      >
    57→        <div className="p-6 border-b border-white/10 flex items-center justify-between bg-white/5">
    58→          <div className="flex items-center gap-3">
    59→            <Sparkles className="text-primary" size={24} />
    60→            <h3 id="generation-modal-title" className="text-xl font-serif font-bold">{isLoading ? 'Génération AEO...' : solution?.title}</h3>
    61→          </div>
    62→          <button onClick={onClose} className="p-2 text-gray-400 hover:text-white" aria-label="Fermer"><X size={20} /></button>
    63→        </div>
    64→
    65→        <div className="flex-1 overflow-y-auto p-8">
    66→          {isLoading ? (
    67→            <div className="flex flex-col items-center justify-center py-20 gap-4">
    68→              <Loader2 className="animate-spin text-primary" size={48} />
    69→              <p className="text-gray-400 animate-pulse">L'IA de CitedBy.ai rédige votre code d'optimisation...</p>
    70→            </div>
    71→          ) : solution && (
    72→            <div className="grid md:grid-cols-12 gap-10">
    73→              <div className="md:col-span-7 space-y-6">
    74→                <div className="p-4 bg-primary/5 border border-primary/10 rounded-xl">
    75→                   <p className="text-sm text-primary/80 leading-relaxed"><span className="font-bold">Objectif citation :</span> {solution.explanation}</p>
    76→                </div>
    77→                <div className="relative">
    78→                  <div className="flex items-center justify-between mb-2">
    79→                    <span className="text-[10px] uppercase font-bold text-gray-500 tracking-widest">{solution.language} code</span>
    80→                    <button className="text-xs text-primary hover:underline flex items-center gap-1"><Copy size={12}/> Copier</button>
    81→                  </div>
    82→                  <pre className="bg-black border border-white/5 p-6 rounded-xl text-sm font-mono text-gray-300 overflow-x-auto">
    83→                    {solution.content}
    84→                  </pre>
    85→                </div>
    86→              </div>
    87→              <div className="md:col-span-5 space-y-6 border-l border-white/5 pl-10">
    88→                 <h4 className="font-bold flex items-center gap-2 text-primary"><ClipboardList size={18}/> Guide d'installation</h4>
    89→                 <div className="space-y-6">
    90→                    {solution.implementationSteps.map((step, i) => (
    91→                      <div key={i} className="flex gap-4">
    92→                        <div className="w-6 h-6 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-xs font-bold text-gray-500 shrink-0">{i+1}</div>
    93→                        <p className="text-sm text-gray-400 leading-relaxed">{step}</p>
    94→                      </div>
    95→                    ))}
    96→                 </div>
    97→              </div>
    98→            </div>
    99→          )}
   100→        </div>
   101→      </div>
   102→    </div>
   103→  );
   104→};
   105→
   106→export default GenerationModal;
   107→

