     3→import React from 'react';
     4→import { Copy, Download } from 'lucide-react';
     5→
     6→interface Props {
     7→  code: string;
     8→  language: 'txt' | 'html' | 'json';
     9→  onCopy?: () => void;
    10→  onDownload?: () => void;
    11→  showControls?: boolean;
    12→}
    13→
    14→const CodePreview: React.FC<Props> = ({ code, language, onCopy, onDownload, showControls = true }) => {
    15→  const handleCopy = async () => {
    16→    try {
    17→      await navigator.clipboard.writeText(code);
    18→      onCopy?.();
    19→    } catch {
    20→      // Pas de clipboard disponible
    21→    }
    22→  };
    23→
    24→  const handleDownload = () => {
    25→    const blob = new Blob([code], { type: 'text/plain;charset=utf-8' });
    26→    const url = URL.createObjectURL(blob);
    27→    const link = document.createElement('a');
    28→    link.href = url;
    29→    link.download = `citedby-${language}.${language === 'html' ? 'html' : language === 'json' ? 'json' : 'txt'}`;
    30→    link.click();
    31→    URL.revokeObjectURL(url);
    32→    onDownload?.();
    33→  };
    34→
    35→  return (
    36→    <div className="bg-[#09090b] border border-white/10 rounded-2xl overflow-hidden shadow-2xl">
    37→      <div className="p-3 bg-white/5 border-b border-white/10 flex items-center justify-between">
    38→        <span className="text-xs text-gray-400 font-bold uppercase tracking-widest">{language}</span>
    39→        {showControls && (
    40→          <div className="flex items-center gap-2">
    41→            <button
    42→              onClick={handleCopy}
    43→              className="p-2 hover:bg-white/10 rounded-lg text-gray-400 hover:text-white transition-colors"
    44→              aria-label="Copier le code"
    45→              title="Copier"
    46→            >
    47→              <Copy size={16} />
    48→            </button>
    49→            <button
    50→              onClick={handleDownload}
    51→              className="p-2 hover:bg-white/10 rounded-lg text-gray-400 hover:text-white transition-colors"
    52→              aria-label="Telecharger le code"
    53→              title="Telecharger"
    54→            >
    55→              <Download size={16} />
    56→            </button>
    57→          </div>
