    12→const App: React.FC = () => {
    13→  const [user, setUser] = useState<User | null>(null);
    14→  const [history, setHistory] = useState<AnalysisResult[]>([]);
    15→  const [isAnalyzing, setIsAnalyzing] = useState(false);
    16→  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
    17→  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]);
    18→  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    19→  const [notifications, setNotifications] = useState<Notification[]>([]);
    20→  const [checkoutData, setCheckoutData] = useState<CheckoutData | null>(null);
    21→  const navigate = useNavigate();
    22→  const location = useLocation();
    23→
    24→  useEffect(() => {
    25→    const savedHistory = localStorage.getItem('aeo_history_v2');
    26→    if (savedHistory) setHistory(JSON.parse(savedHistory));
    27→
    28→    const savedLibrary = localStorage.getItem('aeo_library_v2');
    29→    if (savedLibrary) setSmcLibrary(JSON.parse(savedLibrary));
    30→
    31→    const savedUser = localStorage.getItem('aeo_user');
    32→    if (savedUser) setUser(JSON.parse(savedUser));
    33→  }, []);
    34→
    35→  useEffect(() => {
    36→    localStorage.setItem('aeo_history_v2', JSON.stringify(history));
    37→  }, [history]);
    38→
    39→  useEffect(() => {
    40→    localStorage.setItem('aeo_library_v2', JSON.stringify(smcLibrary));
    41→  }, [smcLibrary]);
    42→
    43→  useEffect(() => {
    44→    if (user) localStorage.setItem('aeo_user', JSON.stringify(user));
    45→    else localStorage.removeItem('aeo_user');
    46→  }, [user]);
    47→
    48→  const notify = useCallback((type: 'success' | 'error' | 'info', message: string) => {
    49→    const id = Date.now().toString();
    50→    setNotifications(prev => [...prev, { id, type, message }]);
    51→  }, []);
    52→
    53→  const dismissNotification = useCallback((id: string) => {
    54→    setNotifications(prev => prev.filter(n => n.id !== id));
    55→  }, []);
    56→
    57→  const handleLogin = (loggedInUser: User) => {
    58→    setUser(loggedInUser);
    59→    if (loggedInUser.credits === 0) {
    60→      navigate(VIEWS.BILLING_CREDITS);
    61→      notify('info', 'Bienvenue ! Veuillez recharger votre compte pour commencer à générer des solutions.');
    62→    } else {
    63→      navigate(VIEWS.ANALYZE);
    64→      notify('success', `Bon retour, ${loggedInUser.name}`);
    65→    }
    66→  };
    67→
    68→  const handleLogout = () => {
    69→    setUser(null);
    70→    navigate(VIEWS.HOME);
    71→    notify('info', 'Déconnexion réussie.');
    72→  };
    73→
    74→  const handleUpdateUser = (updates: Partial<User>) => {
    75→    if (user) {
    76→      setUser({ ...user, ...updates });
    77→    }
    78→  };
    79→
    80→  const handleDeductCredits = (amount: number): boolean => {
    81→    if (!user) {
    82→      navigate(VIEWS.LOGIN);
    83→      notify('error', 'Veuillez vous connecter.');
    84→      return false;
    85→    }
    86→    if (user.credits < amount) {
    87→      notify('error', 'Crédits Gas insuffisants. Redirection vers la recharge.');
    88→      navigate(VIEWS.BILLING_CREDITS);
    89→      return false;
    90→    }
    91→    setUser({ ...user, credits: user.credits - amount });
    92→    return true;
    93→  };
    94→
    95→  const handleAnalyze = async (url: string) => {
    96→    if (isAnalyzing) return;
    97→    if (!handleDeductCredits(CREDIT_COSTS.analysis)) return;
    98→
    99→    setIsAnalyzing(true);
   100→    try {
   101→      const result = await analyzeUrl(url);
   102→      setAnalysisData(result);
   103→      setHistory(prev => [result, ...prev]);
   104→      navigate(VIEWS.PROJECTS);
   105→      notify('success', `Analyse terminée avec succès (-${CREDIT_COSTS.analysis} Gas).`);
   106→    } catch (error) {
   107→      console.error('Analysis failed', error);
   108→      notify('error', "Erreur lors de l'analyse. Veuillez réessayer.");
   109→    } finally {
   110→      setIsAnalyzing(false);
   111→    }
   112→  };
   113→
   114→  const handleConfirmSubscription = () => {
   115→    if (!user || !checkoutData) return;
   116→    let newPlan: PlanTier = 'starter';
   117→    let addedCredits = 0;
   118→
   119→    switch (checkoutData.planName) {
   120→      case 'Starter': newPlan = 'starter'; addedCredits = 50; break;
   121→      case 'Optimizer': newPlan = 'optimizer'; addedCredits = 500; break;
   122→      case 'Agence': newPlan = 'agency'; addedCredits = 2000; break;
   123→      default: newPlan = 'starter'; addedCredits = 50;
   124→    }
   125→
   126→    setUser({ ...user, plan: newPlan, credits: user.credits + addedCredits });
   127→    navigate(VIEWS.PAYMENT_SUCCESS);
   128→  };
   129→
   130→  const handleFinishPaymentFlow = () => {
   131→    setCheckoutData(null);
   132→    navigate(VIEWS.BILLING_DASHBOARD);
   133→  };
   134→
   135→  const handleSaveSolution = useCallback((analysisId: string, recId: string, solution: GeneratedSolution) => {
   136→    const timestamp = new Date().toISOString();
   137→    const solutionWithMeta = { ...solution, timestamp };
   138→    setHistory(prev => prev.map(item => {
   139→      if (item.timestamp === analysisId) {
   140→        return { ...item, generatedSolutions: { ...(item.generatedSolutions || {}), [recId]: solutionWithMeta } };
   141→      }
   142→      return item;
   143→    }));
   144→    notify('success', 'Solution sauvegardée dans le projet.');
   145→  }, [notify]);
   146→
   147→  const handleOpenOrder = (orderId: string) => {
   148→    navigate(buildAgencyOrderPath(orderId));
   149→  };
   150→
   151→  const pathname = location.pathname;
   152→  const isPaymentFlow = pathname.startsWith(VIEWS.PAYMENT);
   153→  const isHome = pathname === VIEWS.HOME;
   154→  const isLogin = pathname === VIEWS.LOGIN;
   155→
   156→  const handleNavigate = useCallback((view: ViewKey) => {
   157→    navigate(view);
   158→  }, [navigate]);
   159→
   160→  return (
   161→    <div className="flex h-screen bg-background text-[#e3e3e3] font-sans overflow-hidden">
   162→      <NotificationSystem notifications={notifications} onDismiss={dismissNotification} />
   163→
   164→      {!isPaymentFlow && !isHome && !isLogin && (
   165→        <Sidebar
   166→          currentView={pathname as ViewKey}
   167→          user={user}
   168→          history={history}
   169→          isMobileMenuOpen={isMobileMenuOpen}
   170→          onCloseMobileMenu={() => setIsMobileMenuOpen(false)}
   171→          onNavigate={handleNavigate}
   172→          onSelectHistory={(result) => { setAnalysisData(result); navigate(VIEWS.PROJECTS); }}
   173→        />
   174→      )}
   175→
   176→      <main className="flex-1 overflow-y-auto relative bg-background flex flex-col">
   177→        {!isPaymentFlow && !isHome && !isLogin && (
   178→          <MobileHeader user={user} onOpenMenu={() => setIsMobileMenuOpen(true)} />
   179→        )}
   180→
   181→        <ErrorBoundary>
   182→          <AppRouter
   183→            user={user}
   184→            history={history}
   185→            smcLibrary={smcLibrary}
   186→            analysisData={analysisData}
   187→            isAnalyzing={isAnalyzing}
   188→            checkoutData={checkoutData}
   189→            onNavigate={handleNavigate}
   190→            onLogin={handleLogin}
   191→            onAnalyze={handleAnalyze}
   192→            onDeductCredits={handleDeductCredits}
   193→            onSaveSolution={handleSaveSolution}
   194→            onAddToLibrary={(item) => setSmcLibrary(prev => [item, ...prev])}
   195→            onSelectAnalysis={setAnalysisData}
   196→            onNewAnalysis={() => navigate(VIEWS.ANALYZE)}
   197→            onConfirmSubscription={handleConfirmSubscription}
   198→            onFinishPaymentFlow={handleFinishPaymentFlow}
   199→            onLogout={handleLogout}
   200→            onUpdateUser={handleUpdateUser}
   201→            notify={notify}
   202→            onOpenOrder={handleOpenOrder}
   203→          />
   204→        </ErrorBoundary>
   205→      </main>
   206→    </div>
   207→  );
   208→};
